            console.log("          '" + qrDataString + "'");
            console.log("[W2.j::c]   --------------------");

            // --- REVERSE ENGINEERING MANIPULATION EXAMPLE ---
            // A reverse engineer could modify 'qrDataString' here to:
            // 1. Redirect a payment to a different address/account.
            // 2. Change a transaction amount or currency.
            // 3. Inject a malicious URL or command into a QR code for a scanner.
            //
            // Example of modification:
            // if (qrDataString.includes("payment_id=")) {
            //     let originalPaymentId = qrDataString.match(/payment_id=([^&]+)/)[1];
            //     let newPaymentId = "MALICIOUS_" + originalPaymentId;
            //     qrDataString = qrDataString.replace(originalPaymentId, newPaymentId);
            //     console.warn("[W2.j::c]   QR Data MODIFIED to: '" + qrDataString + "'");
